        title = data['title']
        created_at = datetime.utcnow()

        db.session.execute(
            db.text('INSERT INTO tasks (title, completed, created_at) VALUES (:title, :completed, :created_at)'),
            {'title': title, 'completed': False, 'created_at': created_at}
        )
        db.session.commit()

        return jsonify({'message': 'Task created successfully'}), 201
