import os
import logging
from datetime import timedelta
from functools import wraps
from flask import Flask, Blueprint, session, redirect, url_for, jsonify, request
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_limiter.errors import RateLimitExceeded

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def create_app():
    """Flask app factory with session-based authentication and rate limiting."""

    # Load SECRET_KEY from environment
    secret_key = os.environ.get('SECRET_KEY')
    if not secret_key:
        raise ValueError("SECRET_KEY environment variable is not set. Please set it before running the app.")

    app = Flask(__name__)

    # Configure app
    app.config['SECRET_KEY'] = secret_key
    app.config['SESSION_COOKIE_SECURE'] = True
    app.config['SESSION_COOKIE_HTTPONLY'] = True
    app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'
    app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

    # Initialize rate limiter with fail-closed behavior
    limiter = Limiter(
        app=app,
        key_func=get_remote_address,
        default_limits=["200 per day", "50 per hour"],
        storage_uri="memory://",
        strategy="fixed-window"
    )

    # Error handler for rate limiting
    @app.errorhandler(RateLimitExceeded)
    def handle_rate_limit_exceeded(e):
        logger.warning(f"Rate limit exceeded for {get_remote_address()}: {str(e)}")
        response = jsonify({"error": "Rate limit exceeded"})
        response.status_code = 429
        response.headers['Retry-After'] = '60'
        return response

    # Error handler for infrastructure errors in rate limiting
    @app.errorhandler(503)
    def handle_service_unavailable(e):
        logger.error(f"Service unavailable: {str(e)}")
        response = jsonify({"error": "Service temporarily unavailable"})
        response.status_code = 503
        response.headers['Retry-After'] = '60'
        return response

    # Authentication decorator
    def login_required(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if 'user_id' not in session:
                logger.info(f"Unauthorized access attempt from {get_remote_address()}")
                return redirect(url_for('auth.login'))
            return f(*args, **kwargs)
        return decorated_function

    # Create auth blueprint
    auth_bp = Blueprint('auth', __name__, url_prefix='/auth')

    @auth_bp.route('/login', methods=['GET', 'POST'])
    @limiter.limit("5 per minute")
    def login():
        if request.method == 'POST':
            # Simple authentication for demo
            username = request.form.get('username')
            password = request.form.get('password')

            # In production, validate against a database
            if username and password:
                session.permanent = True
                session['user_id'] = username
                logger.info(f"User {username} logged in from {get_remote_address()}")
                return redirect(url_for('protected.dashboard'))

            return jsonify({"error": "Invalid credentials"}), 401

        return jsonify({"message": "Login page"}), 200

    @auth_bp.route('/logout', methods=['POST'])
    def logout():
        user_id = session.get('user_id')
        session.clear()
        if user_id:
            logger.info(f"User {user_id} logged out from {get_remote_address()}")
        return redirect(url_for('auth.login'))

    # Create protected blueprint
    protected_bp = Blueprint('protected', __name__, url_prefix='/protected')

    @protected_bp.route('/dashboard')
    @login_required
    @limiter.limit("30 per minute")
    def dashboard():
        user_id = session.get('user_id')
        return jsonify({
            "message": f"Welcome {user_id}",
            "user_id": user_id
        }), 200

    @protected_bp.route('/data')
    @login_required
    @limiter.limit("20 per minute")
    def get_data():
        user_id = session.get('user_id')
        return jsonify({
            "data": "Protected data",
            "user": user_id
        }), 200

    @protected_bp.route('/profile', methods=['GET', 'POST'])
    @login_required
    @limiter.limit("10 per minute")
    def profile():
        user_id = session.get('user_id')

        if request.method == 'POST':
            # Update profile
            logger.info(f"User {user_id} updated profile from {get_remote_address()}")
            return jsonify({"message": "Profile updated"}), 200

        return jsonify({
            "user_id": user_id,
            "profile": "User profile data"
        }), 200

    # Register blueprints
    app.register_blueprint(auth_bp)
    app.register_blueprint(protected_bp)

    # Health check endpoint
    @app.route('/health')
    def health():
        return jsonify({"status": "healthy"}), 200

    # Root endpoint
    @app.route('/')
    def index():
        if 'user_id' in session:
            return redirect(url_for('protected.dashboard'))
        return redirect(url_for('auth.login'))

    return app


if __name__ == '__main__':
    # Set a test SECRET_KEY for development
    os.environ.setdefault('SECRET_KEY', 'dev-secret-key-change-in-production')

    app = create_app()
    app.run(debug=True, host='127.0.0.1', port=5000)
