from flask import Flask, request, g, jsonify
from functools import wraps
import anthropic

app = Flask(__name__)

# Mock rate limiting and user context setup
def setup_user_context():
    g.user = type('User', (), {'id': 'user_123'})()

def check_rate_limit(user_id):
    # Mock implementation - in production, use Redis or similar
    return True

def call_llm(prompt: str, timeout: int) -> str:
    """Call Claude API with the given prompt and timeout."""
    client = anthropic.Anthropic()

    message = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        messages=[
            {"role": "user", "content": prompt}
        ],
        timeout=timeout
    )

    return message.content[0].text

def validate_input():
    """Decorator to validate request input."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Check rate limit
            if not check_rate_limit(g.user.id):
                return jsonify({"error": "Rate limit exceeded"}), 429

            # Validate JSON
            if not request.is_json:
                return jsonify({"error": "Request must be JSON"}), 400

            data = request.get_json()

            # Check required field
            if "text" not in data:
                return jsonify({"error": "Missing required field: text"}), 400

            text = data.get("text", "")

            # Validate text length
            if not isinstance(text, str) or len(text) > 5000:
                return jsonify({"error": "Text must be a string with max 5000 characters"}), 400

            if len(text) == 0:
                return jsonify({"error": "Text cannot be empty"}), 400

            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.before_request
def before_request():
    setup_user_context()

@app.route("/api/summarize", methods=["POST"])
@validate_input()
def summarize():
    """Summarize input text."""
    try:
        data = request.get_json()
        text = data.get("text")

        prompt = f"""Please summarize the following text concisely in 2-3 sentences:

{text}"""

        result = call_llm(prompt, timeout=15)

        if not result or not result.strip():
            return jsonify({"error": "Failed to generate summary"}), 500

        return jsonify({"summary": result.strip()}), 200

    except anthropic.APIError as e:
        return jsonify({"error": "External service error"}), 502
    except Exception as e:
        return jsonify({"error": "External service error"}), 502

@app.route("/api/translate", methods=["POST"])
@validate_input()
def translate():
    """Translate input text to target language."""
    try:
        data = request.get_json()
        text = data.get("text")
        target_language = data.get("target_language", "Spanish")

        prompt = f"""Please translate the following text to {target_language}:

{text}

Provide only the translation, nothing else."""

        result = call_llm(prompt, timeout=15)

        if not result or not result.strip():
            return jsonify({"error": "Failed to generate translation"}), 500

        return jsonify({"translation": result.strip(), "target_language": target_language}), 200

    except anthropic.APIError as e:
        return jsonify({"error": "External service error"}), 502
    except Exception as e:
        return jsonify({"error": "External service error"}), 502

@app.route("/api/classify", methods=["POST"])
@validate_input()
def classify():
    """Classify input text into categories."""
    try:
        data = request.get_json()
        text = data.get("text")

        prompt = f"""Classify the following text into one or more categories from: [Technology, Business, Health, Entertainment, Sports, Politics, Science, Other]

Text: {text}

Respond with only a JSON object with a "categories" key containing a list of applicable categories."""

        result = call_llm(prompt, timeout=15)

        if not result or not result.strip():
            return jsonify({"error": "Failed to classify text"}), 500

        return jsonify({"classification": result.strip()}), 200

    except anthropic.APIError as e:
        return jsonify({"error": "External service error"}), 502
    except Exception as e:
        return jsonify({"error": "External service error"}), 502

if __name__ == "__main__":
    app.run(debug=True)
