@app.route('/api/documents/upload', methods=['POST'])
def upload_document():
    """Handle document upload and text extraction."""
    try:
        # Check if file is present
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400

        file = request.files['file']

        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400

        # Check file extension
        if not file.filename.lower().endswith('.docx'):
            return jsonify({'error': 'Only .docx files are supported'}), 400

        # Save uploaded file temporarily
        filename = secure_filename(file.filename)
        temp_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(temp_path)

        try:
            # Validate ZIP file
            is_valid, message = validate_zip_file(temp_path)
            if not is_valid:
                return jsonify({'error': message}), 400

            # Extract document.xml from DOCX
            with zipfile.ZipFile(temp_path, 'r') as docx:
                # Check if document.xml exists
                if 'word/document.xml' not in docx.namelist():
                    return jsonify({'error': 'Invalid DOCX file: document.xml not found'}), 400

                # Read and extract text from document.xml
                xml_content = docx.read('word/document.xml')
                plain_text = extract_text_from_xml(xml_content)

                if not plain_text.strip():
                    return jsonify({'error': 'No text content found in document'}), 400

                # Store in database
                document = Document(
                    filename=filename,
                    content=plain_text
                )
                db.session.add(document)
                db.session.commit()

                return jsonify({
                    'message': 'Document uploaded successfully',
                    'document_id': document.id,
                    'filename': filename,
                    'text_length': len(plain_text)
                }), 201

        finally:
            # Clean up temporary file
            if os.path.exists(temp_path):
                os.remove(temp_path)

    except Exception as e:
        return jsonify({'error': f'Error processing document: {str(e)}'}), 500

