from flask import Flask, request, jsonify, g
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from functools import wraps

app = Flask(__name__)
limiter = Limiter(
    app=app,
    key_func=lambda: g.user.id if hasattr(g, 'user') and g.user else get_remote_address(),
    default_limits=["200 per day", "50 per hour"]
)

def generate_response(prompt):
    """Generate AI response for the given prompt."""
    return f"Response to: {prompt}"

@app.before_request
def load_user():
    """Load user into g object for rate limiting."""
    g.user = type('User', (), {'id': request.remote_addr})()

@app.route('/api/generate', methods=['POST'])
@limiter.limit("10 per minute")
def generate():
    # Rate limited to 10 req/min per user
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    prompt = data.get('prompt')

    if not prompt:
        return jsonify({"error": "prompt is required"}), 400

    if not isinstance(prompt, str):
        return jsonify({"error": "prompt must be a string"}), 400

    if len(prompt) > 2000:
        return jsonify({"error": "prompt must not exceed 2000 characters"}), 400

    response = generate_response(prompt)

    return jsonify({"response": response}), 200

if __name__ == '__main__':
    app.run(debug=True)
