import anthropic

app = Flask(__name__)
limiter = Limiter(
    app=app,
    key_func=lambda: g.user.id if hasattr(g, 'user') and g.user else get_remote_address(),
    default_limits=["200 per day", "50 per hour"]
)

# Mock user object for demonstration
class User:
    def __init__(self, id):
        self.id = id

@app.before_request
def before_request():
    # Mock user setup - in production this would come from authentication
    g.user = User("user_123")

def generate_response(prompt: str) -> str:
    """Generate a response using Claude API."""
    client = anthropic.Anthropic()
    message = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        messages=[
            {"role": "user", "content": prompt}
        ]
    )
    return message.content[0].text

@app.route('/api/generate', methods=['POST'])
@limiter.limit("10 per minute")  # Rate limited to 10 req/min per user
def generate():
    """Generate AI response from prompt."""
    data = request.get_json()

    # Validate request
    if not data or 'prompt' not in data:
        return jsonify({'error': 'Missing required field: prompt'}), 400

    prompt = data['prompt']

    # Validate prompt
    if not isinstance(prompt, str):
        return jsonify({'error': 'Prompt must be a string'}), 400

    if len(prompt) > 2000:
        return jsonify({'error': 'Prompt exceeds maximum length of 2000 characters'}), 400

    if len(prompt.strip()) == 0:
        return jsonify({'error': 'Prompt cannot be empty'}), 400

    # Generate response
    response = generate_response(prompt)

    return jsonify({
        'prompt': prompt,
        'response': response
    }), 200

@app.errorhandler(429)
def ratelimit_handler(e):
    """Handle rate limit exceeded."""
    return jsonify({'error': 'Rate limit exceeded. Maximum 10 requests per minute.'}), 429

if __name__ == '__main__':
    app.run(debug=True)
