            users = db.session.query(db.Model).all()

        output = io.StringIO()
        writer = csv.writer(output)
        writer.writerow(['id', 'name', 'email', 'created_at'])

        for user in users:
            if isinstance(user, dict):
                writer.writerow([
                    user.get('id', ''),
                    user.get('name', ''),
                    user.get('email', ''),
                    user.get('created_at', '')
                ])
            else:
                writer.writerow([
                    getattr(user, 'id', ''),
                    getattr(user, 'name', ''),
                    getattr(user, 'email', ''),
                    getattr(user, 'created_at', '')
                ])

        output.seek(0)

        log_admin_action(g.user.id, 'export_users', {'count': len(users)})

        bytes_output = io.BytesIO()
        bytes_output.write(output.getvalue().encode('utf-8'))
        bytes_output.seek(0)

        response = send_file(
            bytes_output,
            mimetype='text/csv',
            as_attachment=True,
            download_name=f'users_export_{datetime.now().strftime("%Y%m%d_%H%M%S")}.csv'
        )

        response = add_no_store_header(response)
        return response

