from flask import Blueprint, request, g, make_response
from functools import wraps
import csv
import io
from datetime import datetime

admin_bp = Blueprint('admin', __name__, url_prefix='/admin')

def require_role(role):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if not hasattr(g, 'user') or g.user.role != role:
                return {'error': 'Unauthorized'}, 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def validate_csrf(token):
    return token == getattr(g, 'csrf_token', None)

def log_admin_action(user_id, action_name, details):
    print(f"Admin action: user_id={user_id}, action={action_name}, details={details}")

class User:
    def __init__(self, id, name, email, created_at):
        self.id = id
        self.name = name
        self.email = email
        self.created_at = created_at

def get_all_users():
    users = [
        User(1, "John Doe", "john@example.com", "2023-01-15"),
        User(2, "Jane Smith", "jane@example.com", "2023-02-20"),
        User(3, "Bob Johnson", "bob@example.com", "2023-03-10"),
    ]
    return users

@admin_bp.route('/users/export', methods=['GET'])
@require_role('admin')
def export_users():
    try:
        users = get_all_users()

        output = io.StringIO()
        writer = csv.writer(output)
        writer.writerow(['id', 'name', 'email', 'created_at'])

        for user in users:
            writer.writerow([user.id, user.name, user.email, user.created_at])

        csv_data = output.getvalue()
        output.close()

        log_admin_action(g.user.id, 'export_users', {'count': len(users)})

        response = make_response(csv_data)
        response.headers['Content-Disposition'] = 'attachment; filename=users_export.csv'
        response.headers['Content-Type'] = 'text/csv'
        response.headers['Cache-Control'] = 'no-store'

        return response
    except Exception as e:
        log_admin_action(g.user.id, 'export_users_error', {'error': str(e)})
        response = make_response({'error': 'Failed to export users'}, 500)
        response.headers['Cache-Control'] = 'no-store'
        return response

if __name__ == '__main__':
    from flask import Flask

    app = Flask(__name__)
    app.register_blueprint(admin_bp)

    class MockUser:
        def __init__(self):
            self.id = 1
            self.role = 'admin'

    @app.before_request
    def setup_g():
        g.user = MockUser()
        g.csrf_token = 'test_token'

    with app.test_client() as client:
        response = client.get('/admin/users/export')
        print("Status Code:", response.status_code)
        print("Content-Type:", response.headers.get('Content-Type'))
        print("Cache-Control:", response.headers.get('Cache-Control'))
        print("\nCSV Content:")
        print(response.data.decode('utf-8'))
