  if (req.url.startsWith('/ws/')) {
    wsProxy.upgrade(req, res, head);
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Express server listening on port ${PORT}`);
  console.log(`WebSocket proxy configured for /ws/* -> http://localhost:9000`);
