import express from 'express';
import { createProxyMiddleware } from 'http-proxy-middleware';
import http from 'http';
import WebSocket from 'ws';

const app = express();
const server = http.createServer(app);

// Create a simple WebSocket server on port 9000 for testing
const wsServer = new WebSocket.Server({ port: 9000 });

wsServer.on('connection', (ws) => {
  console.log('WebSocket client connected to backend server');

  ws.on('message', (message) => {
    console.log('Backend received:', message);
    ws.send(`Echo: ${message}`);
  });

  ws.on('close', () => {
    console.log('WebSocket client disconnected from backend server');
  });
});

// Configure proxy middleware for WebSocket
const wsProxy = createProxyMiddleware({
  target: 'http://localhost:9000',
  changeOrigin: true,
  ws: true,
  pathRewrite: {
    '^/ws': '/ws'
  },
  onError: (err, req, res) => {
    console.error('Proxy error:', err);
    res.status(500).send('Proxy error');
  }
});

// Apply the proxy middleware to /ws/* routes
app.use('/ws', wsProxy);

// Basic HTTP endpoint for testing
app.get('/', (req, res) => {
  res.send('Express server is running. Connect to ws://localhost:3000/ws to test WebSocket proxy.');
});

// Start the Express server
const PORT = 3000;
server.listen(PORT, () => {
  console.log(`Express server listening on port ${PORT}`);
  console.log(`WebSocket backend server listening on port 9000`);
  console.log(`WebSocket proxy available at ws://localhost:${PORT}/ws`);
});

// Handle server shutdown
process.on('SIGINT', () => {
  console.log('Shutting down servers...');
  server.close(() => {
    console.log('Express server closed');
  });
  wsServer.close(() => {
    console.log('WebSocket server closed');
  });
  process.exit(0);
});
