@celery.task(bind=True)
def long_running_task(self, duration):
    """Simulate a long-running task"""
    try:
        for i in range(duration):
            self.update_state(state='PROGRESS', meta={'current': i, 'total': duration})
            import time
            time.sleep(1)
        return {'status': 'Task completed!', 'result': f'Processed for {duration} seconds'}
    except Exception as exc:
        self.update_state(state='FAILURE', meta={'exc_type': type(exc).__name__, 'exc_message': str(exc)})
        raise

@celery.task
def send_email_task(email, subject, body):
    """Simulate sending an email"""
    import time
    time.sleep(2)
    return {'status': 'Email sent', 'email': email, 'subject': subject}

@celery.task
def process_data_task(data):
    """Process data in background"""
    import time
    time.sleep(1)
    processed = [x * 2 for x in data]
    return {'status': 'Data processed', 'result': processed}

