            'current': task.info.get('current', 0),
            'total': task.info.get('total', 100),
            'status': f"Processing... {task.info.get('current', 0)}/{task.info.get('total', 100)}"
        }
    elif task.state == 'SUCCESS':
        response = {
            'state': task.state,
            'current': 100,
            'total': 100,
            'status': 'Task completed!',
