import anthropic
import sqlite3
import json

client = anthropic.Anthropic()

def search_documents(search_term: str) -> list[dict]:
    """
    Search documents using Claude with tool use to query FTS5 table.

    Args:
        search_term: User-provided search term from web form

    Returns:
        List of documents with id, title, and snippet
    """

    tools = [
        {
            "name": "query_fts_table",
            "description": "Query the documents_fts FTS5 table to search for documents matching a search term",
            "input_schema": {
                "type": "object",
                "properties": {
                    "search_term": {
                        "type": "string",
                        "description": "The search term to use in the FTS5 query"
                    }
                },
                "required": ["search_term"]
            }
        }
    ]

    messages = [
        {
            "role": "user",
            "content": f"Search for documents matching the term: '{search_term}'. Use the query_fts_table tool to search the documents_fts FTS5 table and return the results with document id, title, and a snippet of the content."
        }
    ]

    response = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        tools=tools,
        messages=messages
    )

    results = []

    while response.stop_reason == "tool_use":
        tool_use_block = None
        for block in response.content:
            if block.type == "tool_use":
                tool_use_block = block
                break

        if not tool_use_block:
            break

        tool_name = tool_use_block.name
        tool_input = tool_use_block.input

        if tool_name == "query_fts_table":
            search_query = tool_input.get("search_term", search_term)

            conn = sqlite3.connect(":memory:")
            cursor = conn.cursor()

            cursor.execute("""
                CREATE VIRTUAL TABLE documents_fts USING fts5(
                    id UNINDEXED,
                    title,
                    content
                )
            """)

            sample_docs = [
                (1, "Python Programming Guide", "Learn Python programming with comprehensive examples and best practices for writing clean, efficient code."),
                (2, "Web Development Basics", "Introduction to web development covering HTML, CSS, and JavaScript fundamentals for building modern websites."),
                (3, "Database Design Patterns", "Explore database design patterns and optimization techniques for building scalable and efficient database systems."),
                (4, "Machine Learning Fundamentals", "Understanding machine learning algorithms, neural networks, and practical applications in data science."),
                (5, "Cloud Computing Architecture", "Cloud infrastructure design, deployment strategies, and best practices for distributed systems.")
            ]

            for doc in sample_docs:
                cursor.execute("INSERT INTO documents_fts VALUES (?, ?, ?)", doc)

            conn.commit()

            cursor.execute("""
                SELECT id, title, snippet(documents_fts, 1, '...', '...', 20) as snippet
                FROM documents_fts
                WHERE documents_fts MATCH ?
                ORDER BY rank
            """, (search_query,))

            rows = cursor.fetchall()

            for row in rows:
                results.append({
                    "id": row[0],
                    "title": row[1],
                    "snippet": row[2]
                })

            conn.close()

            tool_result = json.dumps(results) if results else "No documents found matching the search term."
        else:
            tool_result = "Unknown tool"

        messages.append({
            "role": "assistant",
            "content": response.content
        })

        messages.append({
            "role": "user",
            "content": [
                {
                    "type": "tool_result",
                    "tool_use_id": tool_use_block.id,
                    "content": tool_result
                }
            ]
        })

        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1024,
            tools=tools,
            messages=messages
        )

    return results


if __name__ == "__main__":
    test_searches = [
        "Python programming",
        "database design",
        "machine learning",
        "web development"
    ]

    for search_term in test_searches:
        print(f"\nSearching for: '{search_term}'")
        print("-" * 50)
        results = search_documents(search_term)

        if results:
            for doc in results:
                print(f"ID: {doc['id']}")
                print(f"Title: {doc['title']}")
                print(f"Snippet: {doc['snippet']}")
                print()
        else:
            print("No results found")
