from flask import Flask, request, jsonify
from zod import z, ValidationError
import sqlite3
from contextlib import contextmanager

app = Flask(__name__)

# Database setup
DATABASE = ':memory:'

def get_db():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn

@contextmanager
def get_db_connection():
    conn = get_db()
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()

def init_db():
    with get_db_connection() as conn:
        conn.execute('''
            CREATE TABLE IF NOT EXISTS items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                price REAL NOT NULL
            )
        ''')

# Zod schemas
ItemCreateSchema = z.object({
    'name': z.string().min(1).max(200),
    'price': z.number().gt(0)
})

ItemUpdateSchema = z.object({
    'name': z.string().min(1).max(200),
    'price': z.number().gt(0)
})

# Model function
def update_item(conn, item_id, name, price):
    """Update an existing item with name and price"""
    cursor = conn.cursor()
    cursor.execute(
        'UPDATE items SET name = ?, price = ? WHERE id = ?',
        (name, price, item_id)
    )
    if cursor.rowcount == 0:
        return None
    cursor.execute('SELECT * FROM items WHERE id = ?', (item_id,))
    return dict(cursor.fetchone())

def create_item(conn, name, price):
    """Create a new item"""
    cursor = conn.cursor()
    cursor.execute(
        'INSERT INTO items (name, price) VALUES (?, ?)',
        (name, price)
    )
    item_id = cursor.lastrowid
    cursor.execute('SELECT * FROM items WHERE id = ?', (item_id,))
    return dict(cursor.fetchone())

# Routes
@app.route('/items', methods=['POST'])
def create_item_route():
    """Create a new item with name and price"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        # Validate input
        validated_data = ItemCreateSchema.parse(data)

        with get_db_connection() as conn:
            item = create_item(conn, validated_data['name'], validated_data['price'])

        return jsonify(item), 201

    except ValidationError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/items/<int:item_id>/edit', methods=['POST'])
def edit_item_route(item_id):
    """Update an existing item's name and price"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        # Validate input
        validated_data = ItemUpdateSchema.parse(data)

        with get_db_connection() as conn:
            # Check if item exists
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM items WHERE id = ?', (item_id,))
            if not cursor.fetchone():
                return jsonify({'error': 'Item not found'}), 404

            # Update the item
            item = update_item(conn, item_id, validated_data['name'], validated_data['price'])

        return jsonify(item), 200

    except ValidationError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    init_db()
    app.run(debug=True)
