    """Update an existing item's name and price."""
    data = request.get_json()

    if not data:
        return jsonify({"error": "Request body must be JSON"}), 400

    # Check if item exists
    if item_id not in items_db:
        return jsonify({"error": f"Item with id {item_id} not found"}), 404

    # Get current values if not provided
    name = data.get('name', items_db[item_id]['name'])
    price = data.get('price', items_db[item_id]['price'])

    # Validate name if provided
    if 'name' in data:
        is_valid, error_msg = validate_name(name)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

    # Validate price if provided
    if 'price' in data:
        is_valid, error_msg = validate_price(price)
        if not is_valid:
            return jsonify({"error": error_msg}), 400

    # Use the shared update_item function
    result, status_code = update_item(None, item_id, name, float(price))

    return jsonify(result), status_code

