def notif_icon(notification_type):
    """
    Custom Jinja2 filter that returns an HTML element with an icon and notification type.

    Args:
        notification_type: A string representing the notification type 
                          (e.g., "error", "warning", "info", "success")

    Returns:
        Markup: HTML element with icon and type name
    """
    # Escape the notification_type to prevent XSS attacks
    escaped_type = escape(notification_type)

    # Map notification types to icon classes (using Font Awesome as example)
    icon_map = {
        "error": "fa-circle-xmark",
        "warning": "fa-triangle-exclamation",
        "info": "fa-circle-info",
        "success": "fa-circle-check"
    }

    # Get the icon class, default to info if type not found
    icon_class = icon_map.get(str(notification_type).lower(), "fa-circle-info")

    # Build the HTML with escaped values
    html = f'<div class="notification notification-{escaped_type}"><i class="fas {icon_class}"></i> <span>{escaped_type}</span></div>'

    return Markup(html)

# Register the filter with Flask's Jinja2 environment
