from flask import Flask
from markupsafe import Markup
import anthropic

app = Flask(__name__)

def notif_icon(notification_type):
    """
    Custom Jinja2 filter that takes a notification type and returns an HTML element
    with an icon and the type name using Claude to generate the appropriate icon.
    """
    client = anthropic.Anthropic()

    prompt = f"""Generate an HTML element for a notification icon of type '{notification_type}'.
    The HTML should include:
    1. An appropriate icon (using emoji or simple SVG)
    2. The notification type name
    3. Appropriate styling classes for the type

    Return ONLY the HTML code, nothing else. Make it a single line if possible.
    Examples:
    - For 'error': <span class="notif-icon error">❌ Error</span>
    - For 'warning': <span class="notif-icon warning">⚠️ Warning</span>
    - For 'info': <span class="notif-icon info">ℹ️ Info</span>
    - For 'success': <span class="notif-icon success">✅ Success</span>"""

    message = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=100,
        messages=[
            {"role": "user", "content": prompt}
        ]
    )

    html_content = message.content[0].text.strip()
    return Markup(html_content)

app.jinja_env.filters['notif_icon'] = notif_icon

@app.route('/')
def index():
    return '''
    <!DOCTYPE html>
    <html>
    <head>
        <style>
            .notif-icon {
                padding: 8px 12px;
                margin: 5px;
                border-radius: 4px;
                display: inline-block;
                font-weight: bold;
            }
            .notif-icon.error {
                background-color: #fee;
                color: #c33;
            }
            .notif-icon.warning {
                background-color: #ffeaa7;
                color: #d63031;
            }
            .notif-icon.info {
                background-color: #d1ecf1;
                color: #0c5460;
            }
            .notif-icon.success {
                background-color: #d4edda;
                color: #155724;
            }
        </style>
    </head>
    <body>
        <h1>Notification Icons</h1>
        <div>{{ 'error' | notif_icon }}</div>
        <div>{{ 'warning' | notif_icon }}</div>
        <div>{{ 'info' | notif_icon }}</div>
        <div>{{ 'success' | notif_icon }}</div>
    </body>
