from flask import Blueprint, jsonify, request

bp = Blueprint('categories', __name__, url_prefix='/categories')

# In-memory storage for categories (for demonstration)
categories = {
    1: {'id': 1, 'name': 'Electronics', 'description': 'Electronic devices and gadgets'},
    2: {'id': 2, 'name': 'Books', 'description': 'Physical and digital books'},
    3: {'id': 3, 'name': 'Clothing', 'description': 'Apparel and fashion items'}
}

next_id = 4


@bp.route('/', methods=['GET'])
def list_categories():
    """List all categories"""
    return jsonify(list(categories.values())), 200


@bp.route('/<int:id>', methods=['GET'])
def get_category(id):
    """View a single category"""
    if id not in categories:
        return jsonify({'error': 'Category not found'}), 404
    return jsonify(categories[id]), 200


@bp.route('/', methods=['POST'])
def create_category():
    """Create a new category"""
    global next_id

    data = request.get_json()

    if not data or 'name' not in data:
        return jsonify({'error': 'Name is required'}), 400

    new_category = {
        'id': next_id,
        'name': data['name'],
        'description': data.get('description', '')
    }

    categories[next_id] = new_category
    next_id += 1

    return jsonify(new_category), 201
