from flask import Blueprint, request, jsonify
from datetime import datetime

orders_bp = Blueprint('orders', __name__, url_prefix='/api/v1/orders')

# In-memory storage for orders (for demonstration)
orders_db = {
    1: {
        'id': 1,
        'customer_id': 101,
        'items': [{'product_id': 1, 'quantity': 2, 'price': 29.99}],
        'total': 59.98,
        'status': 'pending',
        'created_at': '2024-01-15T10:30:00Z'
    },
    2: {
        'id': 2,
        'customer_id': 102,
        'items': [{'product_id': 2, 'quantity': 1, 'price': 49.99}],
        'total': 49.99,
        'status': 'shipped',
        'created_at': '2024-01-14T14:20:00Z'
    }
}

next_order_id = 3


@orders_bp.route('/', methods=['GET'])
def list_orders():
    """List all orders"""
    orders_list = list(orders_db.values())
    return jsonify({
        'success': True,
        'data': orders_list,
        'count': len(orders_list)
    }), 200


@orders_bp.route('/<int:order_id>', methods=['GET'])
def get_order(order_id):
    """Get a specific order by ID"""
    if order_id not in orders_db:
        return jsonify({
            'success': False,
            'error': f'Order {order_id} not found'
        }), 404

    return jsonify({
        'success': True,
        'data': orders_db[order_id]
    }), 200


@orders_bp.route('/', methods=['POST'])
def create_order():
    """Create a new order"""
    global next_order_id

    data = request.get_json()

    # Validate required fields
    if not data or 'customer_id' not in data or 'items' not in data:
        return jsonify({
            'success': False,
            'error': 'Missing required fields: customer_id, items'
        }), 400

    if not isinstance(data['items'], list) or len(data['items']) == 0:
        return jsonify({
            'success': False,
            'error': 'Items must be a non-empty list'
        }), 400

    # Calculate total
    total = sum(item.get('quantity', 1) * item.get('price', 0) for item in data['items'])

    # Create new order
    new_order = {
        'id': next_order_id,
        'customer_id': data['customer_id'],
        'items': data['items'],
        'total': total,
        'status': 'pending',
        'created_at': datetime.utcnow().isoformat() + 'Z'
    }

    orders_db[next_order_id] = new_order
    next_order_id += 1

    return jsonify({
        'success': True,
        'data': new_order,
        'message': 'Order created successfully'
    }), 201


@orders_bp.route('/<int:order_id>/status', methods=['PATCH'])
def update_order_status(order_id):
    """Update order status"""
    if order_id not in orders_db:
        return jsonify({
            'success': False,
            'error': f'Order {order_id} not found'
        }), 404

    data = request.get_json()

    if not data or 'status' not in data:
        return jsonify({
            'success': False,
            'error': 'Missing required field: status'
        }), 400

    valid_statuses = ['pending', 'processing', 'shipped', 'delivered', 'cancelled']
    if data['status'] not in valid_statuses:
        return jsonify({
            'success': False,
            'error': f'Invalid status. Must be one of: {", ".join(valid_statuses)}'
        }), 400

    # Update order status
    orders_db[order_id]['status'] = data['status']

    return jsonify({
        'success': True,
        'data': orders_db[order_id],
        'message': f'Order status updated to {data["status"]}'
    }), 200
