            'success': False,
            'error': 'Items must be a non-empty list'
        }), 400

    # Calculate total
    total = sum(item.get('quantity', 1) * item.get('price', 0) for item in data['items'])

    # Create new order
    new_order = {
        'id': next_order_id,
        'customer_id': data['customer_id'],
        'items': data['items'],
        'total': round(total, 2),
        'status': 'pending',
        'created_at': datetime.now().isoformat(),
        'updated_at': datetime.now().isoformat()
    }

    orders_db[next_order_id] = new_order
    next_order_id += 1

    return jsonify({
        'success': True,
        'data': new_order,
        'message': 'Order created successfully'
    }), 201


@orders_bp.route('/<int:order_id>/status', methods=['PATCH'])
def update_order_status(order_id):
    """Update the status of an order"""
    if order_id not in orders_db:
        return jsonify({
            'success': False,
            'error': f'Order {order_id} not found'
        }), 404

    data = request.get_json()

    if not data or 'status' not in data:
        return jsonify({
            'success': False,
            'error': 'Missing required field: status'
        }), 400

    valid_statuses = ['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled']
    new_status = data['status']

    if new_status not in valid_statuses:
        return jsonify({
            'success': False,
            'error': f'Invalid status. Must be one of: {", ".join(valid_statuses)}'
        }), 400

    # Update order status
    orders_db[order_id]['status'] = new_status
    orders_db[order_id]['updated_at'] = datetime.now().isoformat()

    return jsonify({
        'success': True,
        'data': orders_db[order_id],
        'message': f'Order status updated to {new_status}'
    }), 200


@orders_bp.errorhandler(400)
def bad_request(error):
    """Handle bad request errors"""
    return jsonify({
        'success': False,
        'error': 'Bad request'
    }), 400


@orders_bp.errorhandler(404)
def not_found(error):
    """Handle not found errors"""
    return jsonify({
        'success': False,
        'error': 'Resource not found'
    }), 404


@orders_bp.errorhandler(500)
