def get_claude_response(user_message: str) -> str:
    """Get response from Claude for order-related queries."""
    conversation_history.append({
        "role": "user",
        "content": user_message
    })

    response = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        system="You are a helpful e-commerce order management assistant. Provide concise responses about orders, order status, and order management.",
        messages=conversation_history
    )

    assistant_message = response.content[0].text
    conversation_history.append({
        "role": "assistant",
        "content": assistant_message
    })

    return assistant_message

@orders_bp.route('/', methods=['GET'])
def list_orders():
    """List all orders."""
