import Anthropic from "@anthropic-ai/sdk";
import express from "express";

const client = new Anthropic();
const router = express.Router();

// In-memory storage for posts
const posts = [
  {
    slug: "hello-world",
    title: "Hello World",
    content: "This is my first blog post",
  },
  {
    slug: "second-post",
    title: "Second Post",
    content: "This is my second blog post",
  },
];

// GET / - List all posts
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /:slug - Get post by slug
router.get("/:slug", (req, res) => {
  const post = posts.find((p) => p.slug === req.params.slug);
  if (!post) {
    return res.status(404).json({ error: "Post not found" });
  }
  res.json(post);
});

// POST / - Create post
router.post("/", async (req, res) => {
  const { title, content } = req.body;

  if (!title || !content) {
    return res.status(400).json({ error: "Title and content are required" });
  }

  // Use Claude to generate a slug from the title
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 100,
    messages: [
      {
        role: "user",
        content: `Generate a URL-friendly slug from this title. Return only the slug, no other text. Title: "${title}"`,
      },
    ],
  });

  const slug = message.content[0].text.trim().toLowerCase();

  const newPost = { slug, title, content };
  posts.push(newPost);

  res.status(201).json(newPost);
});

// PUT /:slug - Update post
router.put("/:slug", async (req, res) => {
  const { title, content } = req.body;
  const postIndex = posts.findIndex((p) => p.slug === req.params.slug);

  if (postIndex === -1) {
    return res.status(404).json({ error: "Post not found" });
  }

  if (!title && !content) {
    return res
      .status(400)
      .json({ error: "At least title or content is required" });
  }

  // Use Claude to generate a new slug if title is being updated
  let newSlug = req.params.slug;
  if (title) {
    const message = await client.messages.create({
      model: "claude-3-5-sonnet-20241022",
      max_tokens: 100,
      messages: [
        {
          role: "user",
          content: `Generate a URL-friendly slug from this title. Return only the slug, no other text. Title: "${title}"`,
        },
      ],
    });

    newSlug = message.content[0].text.trim().toLowerCase();
  }

  const updatedPost = {
    slug: newSlug,
    title: title || posts[postIndex].title,
    content: content || posts[postIndex].content,
  };

  posts[postIndex] = updatedPost;

  res.json(updatedPost);
});

export default router;
