        language = "de"
    elif any(char in text for char in "áéíóúñ"):
        language = "es"

    return {
        "summary": summary,
        "sentiment": sentiment,
        "confidence": confidence,
        "key_phrases": key_phrases[:5],
        "language": language
    }
